"""
MKT Original Commentary — 1 Kings chapters 15–17 (fill)
Run: python3 scripts/zc-original-1kings-15-17-fill.py

Covers 88 missing verses:
  ch15: 33 missing (v14 already exists)
  ch16: 33 missing (v13 already exists)
  ch17: 22 missing (v1 and v21 already exist)

Key decisions:
- YHWH used throughout (not LORD) to match MKT translational register
- nîr (lamp/dynasty-pledge) distinguished from mᵉnôrāh (lampstand)
- qᵉdēšîm rendered 'male cult devotees' (not 'prostitutes') per lexical range
- gᵉḇîrāh ('queen mother') treated as a semi-official court title
- ʿEtḥbaʿal name analyzed: 'with-Baal' or 'Baal-existent'
- Hiel/Joshua curse (16:34) treated as deliberate allusion to Josh 6:26
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

KINGS1 = {
  "15": {
    "1": '<p><em>Aḇîyām</em> (H38) vs. the parallel form <em>Aḇîyāh</em> (Chronicles) — both names mean \'my father is YHWH,\' but 1 Kings consistently uses the <em>-yām</em> ending, possibly a textual variant or scribal preference. The regnal formula situates him in the synchronistic chronology: eighteenth year of Jeroboam son of Nebat, maintaining the dual-kingdom reckoning throughout the divided-monarchy narrative.</p>',
    "2": '<p><em>šālōš šānîm mālaḵ bîrûšālāim</em> — three years, the shortest reign listed for any Davidic king until Ahaziah. His mother (<em>ʾimmô</em>) is Maacah daughter of Abishalom — the same woman who later appears as the <em>gᵉḇîrāh</em> (queen mother) in v.13. The Abishalom/Absalom identification is debated; she may be a granddaughter of David\'s son Absalom.</p>',
    "3": '<p><em>wayyēleḵ bᵉḵol-ḥaṭṭōʾt ʾāḇîw</em> — he walked in all the sins of his father. The verb <em>hālaḵ bᵉ-</em> (to walk in/after) is the standard Deuteronomistic evaluative formula for apostasy; the preposition <em>bᵉ</em> signals immersion in a pattern of behavior, not single acts. <em>Lᵉḇāḇô</em> (his heart) qualified by <em>šālēm</em> (whole, complete) appears in v.14 as the contrast: Abijam\'s heart was not <em>šālēm ʿim YHWH</em> as his father David\'s was.</p>',
    "4": '<p><em>nîr</em> (H5216) — often rendered \'lamp,\' but the context here is dynastic: YHWH gives David a <em>nîr</em> in Jerusalem, meaning an heir-maintained flame of royal continuity. The term recurs in 11:36 and 15:4 as a covenant pledge. <em>Hāqîm ʾeṯ-bᵉnô ʾaḥărāyw</em> — raising up his son after him: the language of 2 Sam 7:12 (the Davidic covenant), explicitly invoked here to explain why an unworthy king still holds the throne.</p>',
    "5": '<p>The parenthetical exception — <em>raq bᵉḏaḇar ʾûrîyāh haḥittî</em>, \'except in the matter of Uriah the Hittite\' — is the Deuteronomistic historian\'s only qualifying note on David\'s otherwise perfect record. The phrasing \'the Hittite\' distinguishes Uriah by ethnicity and marks the crime as involving a non-Israelite loyal warrior, compounding the moral weight. This exception clause protects the absolute Davidic standard while acknowledging historical reality.</p>',
    "6": '<p><em>mîlḥāmāh hāyᵉṯāh bên-rᵉḥaḇʿām ûḇên-yārāḇʿām</em> — war existed between Rehoboam and Jeroboam throughout Abijam\'s entire life (<em>kol-yᵉmê ḥayyāyw</em>). This is a redactional resumption of the conflict note already made in 14:30. The northern–southern border conflict defines the background of the Abijam and early Asa periods.</p>',
    "7": '<p>The regnal closing formula: <em>wᵉyeter diḇrê ʾaḇîyām wᵉḵol-ʾăšer ʿāśāh</em> — the rest of Abijam\'s acts and all he did are in the chronicles of the kings of Judah. This archival reference appears stereotypically throughout the divided monarchy; it implies a source document beyond the biblical text, now lost. The formula signals narrative closure before the accession notice.</p>',
    "8": '<p><em>wayyiškaḇ ʾaḇîyām ʿim-ʾăḇōṯāyw</em> — the sleep-with-ancestors idiom for natural death, as opposed to \'he died\' (<em>wayyāmot</em>), which may imply violent death. Burial in the city of David (<em>ʿîr dāwîd</em>) marks him as within the legitimate Davidic line despite his failure; David\'s tomb serves as the royal burial standard for Judah.</p>',
    "9": '<p><em>bišnat ʿeśrîm lᵉyārāḇʿām</em> — synchronistic dating: Asa begins in Jeroboam\'s twentieth year. The dual-kingdom dating system requires the historian to maintain two parallel chronologies, cross-referenced at each accession. Asa\'s reign will span 41 years and overlap the reigns of six northern kings.</p>',
    "10": '<p><em>ʾaḇ-ʾimmô māʿăḵāh bat-ʾăḇîšālôm</em> — his \'father\'s mother\' (grandmother) was Maacah daughter of Abishalom, the same woman named as Abijam\'s mother in v.2. This likely reflects the same person serving as <em>gᵉḇîrāh</em> through two reigns, a well-attested ANE practice where the queen mother position was inherited. The Hebrew <em>ʾēm</em> can mean biological mother or functionary in the queen-mother role.</p>',
    "11": '<p><em>wayyaʿaś ʾāsāʾ hayyāšār bᵉʿênê YHWH kᵉdāwîd ʾāḇîw</em> — the positive Davidic standard: Asa did what was right in YHWH\'s eyes, like David his father. This is the highest evaluative grade in the Deuteronomistic system. Only Asa, Jehoshaphat, Hezekiah, and Josiah receive unqualified positive evaluations; Asa\'s is qualified in v.14 by the high-places caveat.</p>',
    "12": '<p><em>wayyaʿaḇer haqqᵉdēšîm min-hāʾāreṣ</em> — he expelled the <em>qᵉdēšîm</em> (H6945, masculine plural from <em>qādôš</em>) from the land. The term denotes male devotees associated with illicit cultic practice; the exact nature of their service remains debated (sacred prostitution vs. other cultic roles), but their association with non-YHWH worship is clear from the surrounding context. <em>Wayyāsar ʾeṯ-kol-haggillulîm</em> — and he removed all the <em>gillulîm</em> (H1544, \'dung-idols,\' a pejorative for divine images). The root may relate to <em>gālal</em> (dung/rolling) — a deliberate slur against idol cults.</p>',
    "13": '<p>Already covered (v14 entry exists); this note is for v13: <em>gᵉḇîrāh</em> (H1377) — queen mother. The term is a semi-official title: the highest-ranking woman in the royal court, not merely a biological relation. Maacah\'s removal (<em>wayyᵉsirēhā min-gᵉḇîrāh</em>) for making a <em>mipleset</em> (H4656, a repulsive/abominable image) for Asherah is significant: this is the only biblical instance of a queen mother being deposed. <em>Wayyiḵrōṯ ʾeṯ-mipleset</em> and burning it at the Kidron valley — <em>Naḥal qiḏrôn</em> was the ritual dump for Jerusalem\'s cultic refuse.</p>',
    "15": '<p><em>wayyāḇēʾ ʾeṯ-qāḏᵉšê ʾāḇîw wᵉʾeṯ-qāḏᵉšāyw</em> — he brought (<em>bôʾ</em> in hiphil) the things his father had dedicated (<em>qāḏᵉšê ʾāḇîw</em>) and the things he himself dedicated (<em>qāḏᵉšāyw</em>) into the house of YHWH. <em>Qāḏᵉšîm</em> here (different from v.12) means \'dedicated/sacred things\' — gold, silver, vessels. This marks Asa as a temple-restorationist, consistent with his overall positive evaluation.</p>',
    "16": '<p><em>mîlḥāmāh hāyᵉṯāh bên-ʾāsāʾ ûḇên-baʿšāʾ melek-yiśrāʾēl kol-yᵉmêhem</em> — war existed between Asa and Baasha king of Israel throughout their days. The resumptive formula echoes v.6 and 14:30. This border warfare defines the political backdrop for Asa\'s appeal to Ben-hadad in v.18–20.</p>',
    "17": '<p><em>wayyaʿal baʿšāʾ melek-yiśrāʾēl ʿal-yᵉhûḏāh wayyiḇen ʾeṯ-hārāmāh</em> — Baasha marched up against Judah and built (<em>bānāh</em>) Ramah. Ramah (5 miles north of Jerusalem) sat astride the main north–south route; fortifying it would have strangled Jerusalem\'s trade and communication. <em>Lᵉḇiltî tēt lāṣēt wālāḇôʾ lᵉʾāsāʾ</em> — so that no one could leave or enter for Asa — describes a blockade function, not just a military fortification.</p>',
    "18": '<p><em>wayyiqqaḥ ʾāsāʾ ʾeṯ-kol-haḵkesef wᵉhazzāhāḇ</em> — Asa took all the silver and gold from the treasuries of the house of YHWH and the house of the king and sent them to Ben-hadad. The emptying of the temple treasury for a military alliance is a recurring pattern in the Judean monarchy (cf. 14:26); here it is strategic desperation. <em>Ḇên-hăḏaḏ ben-ṭaḇrimmôn</em> — Ben-hadad son of Tabrimmon, the Aramean king of Damascus. This is the first appearance of Ben-hadad I in the narrative.</p>',
    "19": '<p><em>bᵉrît bênî ûḇêneḵā</em> — \'a covenant between me and you,\' invoking a prior treaty between fathers. The <em>bᵉrît</em> language is politically freighted: it implies loyalty obligations. Asa sends the silver as a gift (<em>šōḥad</em>, bribe/tribute) to break Ben-hadad\'s existing treaty with Baasha — he is buying a realignment of Aramean foreign policy.</p>',
    "20": '<p><em>wayyišmaʿ ben-hăḏaḏ ʾel-hammelek ʾāsāʾ</em> — Ben-hadad complied. He sent his army commanders against the cities of Israel, striking <em>ʿîyyôn, dān, ʾāḇēl bêṯ-maʿăḵāh</em>, and all Kinnereth — the northern Galilee region. This Aramean intervention into northern Israel\'s border region forced Baasha to abandon the Ramah project.</p>',
    "21": '<p><em>wayyihy kišmōaʿ baʿšāʾ wayyeḥdal miḇnôṯ ʾeṯ-hārāmāh</em> — when Baasha heard, he stopped building Ramah and returned to Tirzah. The verb <em>ḥādal</em> (H2308, to cease/stop) marks the military-political success of Asa\'s diplomatic strategy. Tirzah was the northern kingdom\'s capital from Jeroboam to Omri.</p>',
    "22": '<p><em>wayyašmiʿ hammelek ʾāsāʾ kol-yᵉhûḏāh ʾên nāqî</em> — Asa summoned all Judah, no one exempt (<em>ʾên nāqî</em>, no one released/innocent of the levy). This is a labor conscription (<em>mas ʿōḇēḏ</em>) applied to the entire male population. They removed the stones and timber Baasha had used at Ramah and built with them Geba of Benjamin and Mizpah — recycling enemy fortification material for Judean frontier defense.</p>',
    "23": '<p>The closing formula for Asa: <em>wᵉḵol-gᵉḇûrāṯô</em>, all his might, plus the note that in his old age (<em>bᵉʿēṯ ziḵnāṯô</em>) he was diseased in his feet (<em>ḥālāh ʾeṯ-raglāyw</em>). The foot disease may be gout or arteriosclerosis; 2 Chr 16:12 adds that he sought physicians rather than YHWH, a theological note absent here in Kings.</p>',
    "24": '<p><em>wayyiškaḇ ʾāsāʾ ʿim-ʾăḇōṯāyw wayyiqqāḇēr ʿim-ʾăḇōṯāyw bᵉʿîr dāwîd ʾāḇîw</em> — Asa rested with his ancestors and was buried with them in the city of David his father. The burial formula confirms dynastic continuity: even qualified kings receive the Davidic burial honor. His son Jehoshaphat reigned in his place — the succession formula (<em>wayyimloḵ yᵉhôšāpāṭ bᵉnô taḥtāyw</em>).</p>',
    "25": '<p><em>wᵉnāḏāḇ ben-yārāḇʿām mālaḵ ʿal-yiśrāʾēl bišnat šᵉtayim lᵉʾāsāʾ</em> — Nadab son of Jeroboam became king of Israel in Asa\'s second year, reigning two years. The synchronistic dating resumes for the northern kingdom. Nadab\'s brief reign anticipates the pattern of short, violent tenures that characterize the northern monarchy after Jeroboam.</p>',
    "26": '<p><em>wayyaʿaś hārāʿ bᵉʿênê YHWH wayyēleḵ bᵉḏereḵ ʾāḇîw ûḇᵉḥaṭṭāʾṯô</em> — the negative Jeroboamic evaluation formula, applied here to Nadab. Walking in the way (<em>dereḵ</em>) of his father and in the sin (<em>ḥaṭṭāʾt</em>) by which Jeroboam caused Israel to sin — this phrase recurs verbatim for every unqualified northern king, a Deuteronomistic refrain anchoring the entire narrative of northern failure to the founding apostasy.</p>',
    "27": '<p><em>wayyiqšor ʿālāyw baʿšāʾ ben-ʾăḥîyāh lᵉḇêṯ-yiśāśḵār</em> — Baasha son of Ahijah from the tribe of Issachar conspired (<em>qāšar</em>, H7194, to bind/conspire) against Nadab. The verb <em>qāšar</em> is the standard term for palace coups in Kings; its occurrence marks the fragile politics of the northern monarchy. Gibbethon was a Philistine-held town on the Dan–Ephraim border, where Israel was engaged in siege when the coup occurred — the army was away from the capital.</p>',
    "28": '<p><em>wayyamîṯēhû baʿšāʾ bišnat šālōš lᵉʾāsāʾ</em> — Baasha killed him in Asa\'s third year and reigned in his place. The dynastic shift from Jeroboam\'s house to Baasha\'s is complete in a single verse. The brutal efficiency of the coup — striking during an active siege — is a realistic political-military detail.</p>',
    "29": '<p><em>wayyᵉhî kᵉmalḵô hikkāh ʾeṯ-kol-bêṯ yārāḇʿām lōʾ hišʾîr kol-nᵉšāmāh lᵉyārāḇʿām</em> — as soon as he became king, he struck down the entire house of Jeroboam, leaving not one soul (<em>nᵉšāmāh</em>, H5397). The term <em>nᵉšāmāh</em> (breath/soul/living being) here means \'a single living person\' — total dynastic elimination. The hiphil of <em>šāʾar</em> (leave behind) with <em>lōʾ</em> is the standard formula for total annihilation of a royal house (cf. 16:11).</p>',
    "30": '<p><em>ʿal-ḥaṭṭōʾṯ yārāḇʿām ʾăšer ḥāṭāʾ waʾăšer heḥᵉṭîʾ ʾeṯ-yiśrāʾēl</em> — the theological rationale: because of the sins Jeroboam sinned and caused Israel to sin — the double accusation (<em>ḥāṭāʾ</em> and <em>heḥᵉṭîʾ</em> hiphil) marks both personal guilt and corporate causation. The phrase <em>bᵉkaʿᵃsô ʾăšer hiḵʿîs ʾeṯ-YHWH</em> — by the provocation with which he provoked YHWH — introduces <em>kaʿas</em> (H3708, vexation/anger-provocation), a term for idolatry-induced divine anger.</p>',
    "31": '<p>The archival closing formula for Nadab: <em>wᵉyeter diḇrê nāḏāḇ wᵉḵol-ʾăšer ʿāśāh</em> — the rest of Nadab\'s acts and all he did are written in the chronicles of the kings of Israel. The reference to a northern chronicles document parallels the Judean source in v.7; both are now lost but imply court records underlying the Deuteronomistic account.</p>',
    "32": '<p>Resumptive war notice: <em>mîlḥāmāh hāyᵉṯāh bên-ʾāsāʾ ûḇên-baʿšāʾ melek-yiśrāʾēl kol-yᵉmêhem</em> — war between Asa and Baasha all their days. This repetition of v.16 brackets the Nadab episode and resumes the Asa–Baasha narrative thread. Repetitive resumption is a characteristic feature of the Deuteronomistic compositional technique.</p>',
    "33": '<p><em>bišnat šālōš lᵉʾāsāʾ melek yᵉhûḏāh mālaḵ baʿšāʾ ben-ʾăḥîyāh ʿal-kol-yiśrāʾēl</em> — Baasha\'s accession in Asa\'s third year at Tirzah (<em>ṯirṣāh</em>), ruling the full (<em>kol</em>) Israel. The 24-year reign is the longest of any non-Omride northern king. Tirzah (modern Tell el-Farah North) served as the northern capital until Omri founded Samaria in 16:24.</p>',
    "34": '<p><em>wayyaʿaś hārāʿ bᵉʿênê YHWH wayyēleḵ bᵉḏereḵ yārāḇʿām</em> — the same Jeroboamic evaluation formula applied to Baasha. The irony is sharp: Baasha was raised up to judge Jeroboam\'s house (16:2–3) but walks in the same sin he was sent to punish. This pattern — instrument of judgment becoming the next subject of judgment — is a Deuteronomistic theological motif.</p>'
  },
  "16": {
    "1": '<p><em>wayᵉhî dᵉḇar-YHWH ʾel-yēhûʾ ben-ḥănānî ʾel-baʿšāʾ</em> — the word of YHWH came to Jehu son of Hanani against Baasha. The prophetic messenger formula (<em>dᵉḇar-YHWH hāyāh ʾel</em>) marks this as a formal oracle. Jehu son of Hanani is a northern prophet; his father Hanani appears in 2 Chr 16:7 as the seer who rebuked Asa. The oracle against Baasha mirrors the oracle against Jeroboam (14:1–18).</p>',
    "2": '<p><em>yaʿan ʾăšer hărîmōṯîḵā min-hāʾāpār</em> — because I lifted you from the dust. The elevation-from-nothing formula (<em>min-hāʾāpār</em>, from the dust) echoes 1 Sam 2:8 and reflects the standard covenant-grant language: the sovereign elevates a vassal from obscurity and places him over the people. Baasha\'s failure to reciprocate this patronage with covenant loyalty is the charge.</p>',
    "3": '<p><em>hinnᵉnî mᵉbaʿer ʾaḥărê baʿšāʾ wᵉʾaḥărê bêṯô</em> — I am about to sweep away (<em>bāʿar</em>, H1197, to burn/sweep/consume) after Baasha and his house. The same verb was used against Jeroboam (14:10) and will recur for Ahab (21:21), creating a theological pattern: each dynasty that walks in Jeroboam\'s sin receives the same consuming judgment. <em>Wᵉnāṯattî bêṯᵉḵā kᵉḇêṯ yārāḇʿām ben-nᵉḇāṭ</em> — I will make your house like the house of Jeroboam.</p>',
    "4": '<p><em>hammēṯ lᵉḇaʿšāʾ bāʿîr yōʾḵᵉlû haqqᵉlāḇîm</em> — the one who dies in the city, the dogs will eat him; the one who dies in the field, the birds of the air will eat him. This curse formula (also in 14:11 for Jeroboam\'s house) denies proper burial — one of the worst fates in the ANE honor-shame economy. Proper burial (<em>qᵉḇûrāh</em>) was essential for posthumous honor; dogs and birds consuming the corpse represented maximal disgrace.</p>',
    "5": '<p>The archival closing formula for Baasha: <em>wᵉyeter diḇrê baʿšāʾ wʾăšer ʿāśāh ûgᵉḇûrāṯô</em> — the rest of Baasha\'s acts and all he did and his might are in the chronicles of the kings of Israel. The addition of <em>gᵉḇûrāṯô</em> (his might/valor) suggests military exploits recorded elsewhere; the canonical account focuses on the theological verdict.</p>',
    "6": '<p><em>wayyiškaḇ baʿšāʾ ʿim-ʾăḇōṯāyw wayyiqqāḇēr bᵉṯirṣāh</em> — Baasha rested with his ancestors and was buried at Tirzah. Despite the oracle against his house (v.3–4), Baasha himself receives the conventional \'rest with ancestors\' and burial — the dynastic elimination falls on his son Elah. His son Elah reigned in his place: the <em>taḥtāyw</em> succession formula maintains narrative continuity even for a doomed dynasty.</p>',
    "7": '<p><em>wᵉgam bᵉyad-yēhûʾ ben-ḥănānî hānāḇîʾ hāyāh dᵉḇar-YHWH ʾel-baʿšāʾ wᵉʾel-bêṯô</em> — and also through Jehu son of Hanani the prophet, the word of YHWH came against Baasha and his house — the double oracle structure: the prophetic word is both the narrative explanation (v.1–4) and here confirmed as having come through the prophet. The clause <em>ʿal-kol-hārāʿāh ʾăšer ʿāśāh</em> (for all the evil he did) adds the specific charge of provoking YHWH to anger with the work of his hands.</p>',
    "8": '<p><em>bišnat ʿeśrîm wᵉšēš lᵉʾāsāʾ melek yᵉhûḏāh mālaḵ ʾēlāh ben-baʿšāʾ ʿal-yiśrāʾēl bᵉṯirṣāh šᵉnātayim</em> — Elah son of Baasha became king of Israel in Asa\'s twenty-sixth year, reigning two years at Tirzah. The two-year reign is the minimum before conspiracy overtakes him. His reign contains no evaluative formula — the historian reserves comment until the conspiracy narrative makes the theological point implicit.</p>',
    "9": '<p><em>wayyiqšor ʿālāyw zimrî śar maḥᵃṣît harreḵeḇ</em> — Zimri, commander of half his chariot force (<em>maḥᵃṣît harreḵeḇ</em> — half the chariotry), conspired against Elah. The rank marks Zimri as a senior military officer, not a common soldier. The conspiracy occurs while Elah was drinking himself drunk (<em>šāṯāh šikḵôr</em>) in the house of Arza, steward of the palace at Tirzah — the detail of vulnerability (drunkenness, location away from armed guard) explains the coup\'s success.</p>',
    "10": '<p><em>wayyāḇōʾ zimrî wayyakkēhû wayyᵉmîṯēhû bišnat ʿeśrîm wᵉšeḇaʿ lᵉʾāsāʾ</em> — Zimri came in, struck him, and killed him in Asa\'s twenty-seventh year, and reigned in his place. The narrative\'s speed — three verbs, three actions — mirrors the coup\'s summary brutality. Zimri\'s reign begins and will end within seven days (v.15).</p>',
    "11": '<p><em>wayyᵉhî bᵉmalḵô kᵉšiḇtô ʿal-kissᵉʾô hikkāh ʾeṯ-kol-bêṯ baʿšāʾ lōʾ-hišʾîr lô maštin bᵉqîr</em> — as soon as he sat on the throne, he struck down all the house of Baasha; he left not one male (<em>maštin bᵉqîr</em>, literally \'one urinating against a wall\' — a coarse idiom for any male). This phrase (also in 14:10; 21:21; 1 Sam 25:22) is a Deuteronomistic formula for total male elimination. <em>Wᵉgōʾălāyw wᵉmērēʿēhû</em> — his relatives and friends (blood-avengers and allies) — are also eliminated, cutting off any future revenge claim.</p>',
    "12": '<p><em>wayyašmēd zimrî ʾēṯ kol-bêṯ baʿšāʾ kᵉḏiḇar YHWH ʾăšer dibber ʾel-baʿšāʾ bᵉyad yēhûʾ hannāḇîʾ</em> — Zimri destroyed the entire house of Baasha in fulfillment of the word of YHWH that Jehu the prophet had spoken against Baasha. The fulfillment formula (<em>kᵉḏiḇar YHWH ʾăšer dibber</em>) closes the prophetic oracle that opened in v.1–4. Even a seven-day usurper can be the instrument of divine prophetic fulfillment — the theology does not require moral worthiness in the instrument.</p>',
    "14": '<p>Closing formula for Elah: <em>wᵉyeter diḇrê ʾēlāh wᵉḵol-ʾăšer ʿāśāh</em> — in the chronicles of the kings of Israel. The brevity of the Elah entry is consistent with the narrative\'s focus on the theological pattern rather than the historical details of short, failed reigns.</p>',
    "15": '<p><em>bišnat ʿeśrîm wᵉšeḇaʿ lᵉʾāsāʾ mālaḵ zimrî šiḇʿat yāmîm bᵉṯirṣāh</em> — Zimri reigned seven days at Tirzah in Asa\'s twenty-seventh year. The seven-day duration is the shortest royal tenure in the Kings narrative, a record of failure. The army (<em>hāʿām</em>, the people/troops) was encamped against Gibbethon of the Philistines — the same siege at which Baasha killed Nadab (15:27), now resumed or still ongoing.</p>',
    "16": '<p><em>wayyišmᵉʿû hāʿām hahōnîm lēʾmōr qāšar zimrî wᵉgam hikkāh ʾeṯ-hammelek</em> — the encamped troops heard that Zimri had conspired and had also killed the king, and all Israel made Omri the army commander king that day at the camp. The field election — <em>wayyamlîḵû ʾeṯ-ʿomrî śar-haṣṣāḇāʾ ʿal-yiśrāʾēl bayyôm hahûʾ bammaḥăneh</em> — is an improvised military acclamation, not a formal succession.</p>',
    "17": '<p><em>wayyaʿal ʿomrî wᵉḵol-yiśrāʾēl ʿimmô miggibbeṯôn wayyāṣurû ʿal-ṯirṣāh</em> — Omri marched up from Gibbethon with all Israel and besieged Tirzah. The siege of the capital by the army against Zimri is a civil war in microcosm: the field army vs. the recently established palace coup. The verb <em>ṣûr</em> (to besiege) marks Tirzah as an enemy city within Israel\'s own territory.</p>',
    "18": '<p><em>wayyᵉhî kirʾōṯ zimrî kî-nilkᵉḏāh hāʿîr wayyāḇōʾ ʾel-bîraṯ bêṯ-hammelek wayyiśrōp ʿālāyw ʾeṯ-bêṯ-hammelek bāʾēš wayyāmāṯ</em> — when Zimri saw that the city was captured, he went into the inner citadel (<em>bîrāh</em>, H1002) of the palace and burned the palace over himself (<em>wayyiśrōp ʿālāyw</em>) and died. Suicide by palace arson — a defiant final act that deprives his conqueror of both a captive and a trophy; the palace becomes his funeral pyre.</p>',
    "19": '<p><em>ʿal-ḥaṭṭōʾṯāyw ʾăšer ḥāṭāʾ laʿăśôṯ hārāʿ bᵉʿênê YHWH</em> — Zimri\'s death is given the standard theological verdict despite the seven-day reign; he walked in the way of Jeroboam and in the sins by which Jeroboam caused Israel to sin. The Deuteronomistic formula operates independently of duration — even a seven-day king who followed the founding apostasy receives the Jeroboamic verdict.</p>',
    "20": '<p>The archival reference for Zimri: <em>wᵉyeter diḇrê zimrî wᵉqišrô ʾăšer qāšar</em> — the rest of Zimri\'s acts and his conspiracy that he conspired are in the chronicles of the kings of Israel. The closing formula here uniquely adds the conspiracy detail (<em>qišrô ʾăšer qāšar</em>) — the conspiracy is the defining act of a seven-day reign with nothing else to record.</p>',
    "21": '<p><em>ʾāz yēḥāleq hāʿām yiśrāʾēl laḥᵃṣî</em> — then the people of Israel were divided in half. The split is between Tibni son of Ginath (backed by half the population) and Omri (backed by the other half). The civil war between these two factions parallels the earlier north-south split; within the northern kingdom, the military/Omride faction fights a civilian/Ginath faction for four years (cf. v.23\'s dating).</p>',
    "22": '<p><em>wayyeḥᵉzaq hāʿām ʾăšer ʾaḥărê ʿomrî ʾeṯ-hāʿām ʾăšer ʾaḥărê ṯiḇnî</em> — the people behind Omri prevailed over the people behind Tibni. <em>Wayyāmāṯ ṯiḇnî</em> — Tibni died, leaving the cause of his faction. The cause of death is not stated; the text is indifferent to the manner, only the result. Omri was king — the terse accession formula closes the civil war narrative.</p>',
    "23": '<p><em>bišnat šᵉlōšîm wᵉʾaḥat lᵉʾāsāʾ melek yᵉhûḏāh mālaḵ ʿomrî ʾel-yiśrāʾēl šᵉtêm ʿeśrēh šānāh</em> — Omri became king in Asa\'s thirty-first year; he reigned twelve years. Six years in Tirzah (<em>ṯirṣāh</em>) then moved to Samaria. The twelve-year figure and the six-at-Tirzah note create a chronological precision that anchors the Omride dynasty in the synchronistic system.</p>',
    "24": '<p><em>wayyiqen ʾeṯ-hār-šōmᵉrôn mēʾēṯ-šemer bišᵉnê kikkārim-kesef</em> — he bought the hill of Samaria (<em>har-šōmᵉrôn</em>) from Shemer for two talents of silver. The Hebrew etymology is explicit: the city name <em>Šōmᵉrôn</em> derives from the seller\'s name <em>Šemer</em> — Omri named the city after the former owner of the hill, an unusual naming convention that may preserve legal or honorific memory of the transaction. Two talents of silver (about 68 kg) for a strategic hill — a significant but not extraordinary price for a royal land purchase.</p>',
    "25": '<p><em>wayyaʿaś ʿomrî hārāʿ bᵉʿênê YHWH wayyāreʿ mikkōl ʾăšer lᵉpānāyw</em> — Omri did more evil than all before him. The comparative formula <em>wayyāreʿ mikkōl</em> (did worse than all) is escalating: each northern dynasty receives a slightly worse verdict than the last, building to Ahab\'s climactic judgment in v.30–33. The Deuteronomistic theology of progressive corruption uses this comparative rhetoric to explain the eventual Assyrian destruction.</p>',
    "26": '<p><em>wayyēleḵ bᵉḵol-dereḵ yārāḇʿām ben-nᵉḇāṭ ûḇᵉḥaṭṭōʾṯāyw ʾăšer heḥᵉṭîʾ ʾeṯ-yiśrāʾēl</em> — Omri walked fully in the way of Jeroboam and in the sins by which Jeroboam caused Israel to sin, provoking YHWH the God of Israel to anger with their <em>haḇlêhem</em> (H1892, vapors/vanities/idols — the same word used in Ecclesiastes for futility). <em>Haḇlîm</em> is a secondary pejorative for idols, implying their insubstantiality.</p>',
    "27": '<p>Archival formula for Omri: <em>wᵉyeter diḇrê ʿomrî ʾăšer ʿāśāh ûgᵉḇûrāṯô ʾăšer gāḇar</em> — the rest of Omri\'s acts and the strength he showed are in the chronicles of the kings of Israel. The Assyrian records call Israel \'the house of Omri\' (bît-ḥumrî) for well over a century after his dynasty ended, indicating Omri\'s actual historical significance far exceeds what the Deuteronomistic account allots him — the theological evaluation has compressed a politically major reign.</p>',
    "28": '<p><em>wayyiškaḇ ʿomrî ʿim-ʾăḇōṯāyw wayyiqqāḇēr bᵉšōmᵉrôn</em> — Omri rested with his ancestors and was buried in Samaria — the first king buried in his own newly founded capital rather than an ancestral city. His son Ahab reigned in his place: the succession formula introduces the figure who will dominate the next 10 chapters.</p>',
    "29": '<p><em>wᵉʾaḥāḇ ben-ʿomrî mālaḵ ʿal-yiśrāʾēl bišnat šᵉlōšîm wᵉšᵉmōneh šānāh lᵉʾāsāʾ</em> — Ahab son of Omri became king in Asa\'s thirty-eighth year, reigning 22 years. The synchronistic dating places him deep within the long Asa reign. The narrative will devote more space to Ahab than to any other northern king — not for his political achievements but for the religious confrontation with Elijah.</p>',
    "30": '<p><em>wayyaʿaś ʾaḥāḇ ben-ʿomrî hārāʿ bᵉʿênê YHWH mikkōl ʾăšer lᵉpānāyw</em> — Ahab did more evil than all before him, continuing the escalating comparative formula from v.25. The historian uses the superlative not for hyperbole but as theological periodization: Ahab represents the culmination of northern apostasy, requiring the extraordinary prophetic response of Elijah and Elisha.</p>',
    "31": '<p><em>wayyᵉhî hănaqlāh lekteṯ bᵉḥaṭṭōʾṯ yārāḇʿām ben-nᵉḇāṭ wayyiqqaḥ ʾišṯāh ʾeṯ-ʾîzeḇel bat-ʾeṯbaʿal melek ṣîḏōnîm</em> — as if it were a light thing (rhetorically ironic <em>hănaqlāh</em> construction), he took to wife Jezebel daughter of Ethbaal king of the Sidonians. <em>ʾîzeḇel</em> (H348) — the etymology is debated: possibly \'where is the prince?\' (a cultic mourning formula for Baal) or \'Baal is exalted.\' <em>ʾeṯbaʿal</em> (\'with-Baal\' or \'Baal lives\') identifies her father as a Phoenician king with explicit Baal devotion. The marriage brings Baal worship into the northern royal court as a state-sponsored institution.</p>',
    "32": '<p><em>wayyāqem mizbēaḥ labbāʿal bêṯ habbāʿal ʾăšer bānāh bᵉšōmᵉrôn</em> — he set up an altar for Baal in the temple of Baal that he built in Samaria. The construction of a royal Baal temple in the capital — distinct from the golden-calf shrines at Bethel and Dan (Jeroboam\'s sin) — represents a qualitative escalation: now foreign Phoenician Baal (not an altered YHWH cult) is institutionalized in the capital. This is the specific act that distinguishes Ahab\'s apostasy from all predecessors.</p>',
    "33": '<p><em>wayyaʿaś ʾaḥāḇ ʾeṯ-hāʾăšērāh</em> — Ahab also made the Asherah pole (<em>ʾăšērāh</em>, H842 — both the goddess and her sacred wooden symbol). <em>Wayyōsep ʾaḥāḇ laʿăśôṯ lᵉhaḵʿîs ʾeṯ-YHWH ʾĕlōhê yiśrāʾēl mikkōl malkê yiśrāʾēl ʾăšer hāyû lᵉpānāyw</em> — Ahab did more to provoke YHWH than all the kings before him — the absolute superlative closes the escalating series (vv.25, 30, 33), establishing Ahab as the nadir of northern kingship and the necessary context for Elijah\'s ministry.</p>',
    "34": '<p><em>bᵉyāmāyw bānāh ḥîʾēl habbêṯᵉʾēlî ʾeṯ-yᵉrîḥōh</em> — in his days Hiel the Bethelite rebuilt Jericho. He laid its foundation at the cost of Abiram his firstborn and set up its gates at the cost of Segub his youngest son — <em>bᵉʾăḇîrām bᵉḵōrô yaṣṣîḇ ûḇîśgûḇ ṣᵉʿîrô nîṣṣaḇ dᵉlāṯêyhā</em>. The fulfillment of Joshua\'s curse (Josh 6:26: \'at the cost of his firstborn he shall lay its foundation, and at the cost of his youngest son he shall set up its gates\') — the vocabulary of Joshua and 1 Kings 16:34 are verbally identical. Whether the deaths were coincidental or literal fulfillment of the oath, the historian presents them as prophetic completion: the Elijah narrative will open immediately after this notice, connecting Joshua\'s ancient word to the new prophetic era.</p>'
  },
  "17": {
    "2": '<p><em>wayᵉhî dᵉḇar-YHWH ʾēlāyw lēʾmōr</em> — the word of YHWH came to him, saying. The divine-word reception formula occurs three times in ch.17 (vv.2, 8, 14/the oracle form), structuring the chapter as three successive divine directions. The brevity of v.2 — no elaboration, just the formula — intensifies the sense of immediate divine command after Elijah\'s drought announcement.</p>',
    "3": '<p><em>leḵ-lᵉḵā miṭṭāh wᵉp̄ānîṯā lᵉḵā qēḏmāh wᵉnistaraṯṯā bᵉnaḥal kᵉrîṯ</em> — go from here, turn east, and hide yourself by the brook Cherith. <em>Nistaraṯṭā</em> (hithpael of <em>sātar</em>, to hide/conceal) — the command to hiddenness is theologically significant: Elijah disappears from Ahab\'s reach at YHWH\'s direction, not from fear. Cherith (<em>kᵉrîṯ</em>) east of the Jordan remains unidentified; the Jordan crossing removes Elijah from Ahab\'s jurisdiction entirely.</p>',
    "4": '<p><em>wᵉhāyāh min-hannaḥal tišṯeh wᵉʾeṯ-hāʿōrᵉḇîm ṣiwwîṯî lᵉkalkēlkāh šām</em> — you will drink from the brook, and I have commanded (<em>ṣiwwîṯî</em>, perfect — already commanded) the ravens (<em>hāʿōrᵉḇîm</em>, H6158) to feed you there. The ravens were ritually unclean birds (Lev 11:15) — their use as divine provision agents subverts purity categories to serve prophetic sustenance. The perfect tense of the divine command (<em>ṣiwwîṯî</em>) treats the instruction as already accomplished before Elijah moves.</p>',
    "5": '<p><em>wayyēleḵ wayyaʿaś kidbar YHWH</em> — he went and did according to the word of YHWH. The obedience report uses the exact formula of Abrahamic compliance (Gen 22:3 uses the same pattern). <em>Wayyēšeḇ bᵉnaḥal kᵉrîṯ</em> — he settled (<em>yāšaḇ</em>) by the brook Cherith — not a temporary stop but an established dwelling, underscoring the months-long duration of the provision.</p>',
    "6": '<p><em>wᵉhāʿōrᵉḇîm mᵉḇîʾîm lô leḥem ûḇāśār babbōqer wᵉleḥem ûḇāśār bāʿereḇ</em> — the ravens brought him bread and meat in the morning and bread and meat in the evening. The double provision — morning and evening — mirrors the manna pattern (Exod 16:8, 12–13) and the Passover timing, connecting Elijah\'s sustenance to the wilderness provision of the Mosaic period. The source of the ravens\' bread and meat is unspecified — the text focuses on the act of provision, not its logistics.</p>',
    "7": '<p><em>wayyᵉhî miqṣēh yāmîm wayyiḇaš hannaḥal kî lōʾ-hāyāh gešem bāʾāreṣ</em> — after some time the brook dried up because there was no rain in the land. The phrase <em>miqṣēh yāmîm</em> (after the end of days) is deliberately vague — the drought was progressive, not instantaneous. The drying of Cherith forces the next divine direction; YHWH\'s provision does not insulate Elijah from the drought\'s effects but redirects him through them.</p>',
    "8": '<p><em>wayyᵉhî dᵉḇar-YHWH ʾēlāyw lēʾmōr</em> — the second occurrence of the divine-word formula in ch.17 (cf. v.2). Its repetition at the moment of crisis (the dried brook) signals that YHWH\'s direction is responsive to changed circumstances, not static. The prophet is not left without instruction when his provision source fails.</p>',
    "9": '<p><em>qûm leḵ ṣārᵉpāṯāh ʾăšer lᵉṣîḏôn wᵉyāšaḇtā šām</em> — go to Zarephath which belongs to Sidon and live there. Zarephath (<em>ṣārᵉpaṯ</em>, H6886 — modern Sarafand in Lebanon) was in Phoenician territory, the homeland of Jezebel\'s father Ethbaal. The theological irony: YHWH sends his prophet to the pagan widow in the land of Baal worship, not to any of Israel\'s many widows (Luke 4:25–26 makes this explicit). <em>Ḥinnēh ṣiwwîṯî šām ʾišāh ʾalmānāh lᵉḵalkᵉlāk</em> — I have commanded a widow there to feed you. The divine <em>ṣiwwîṯî</em> perfect reappears: the provision is already arranged before Elijah arrives.</p>',
    "10": '<p><em>wayyāqom wayyēleḵ ṣārᵉpāṯāh</em> — Elijah rose and went to Zarephath. The obedience formula echoes v.5. At the city gate (<em>pēṯaḥ hāʿîr</em>) he finds the widow gathering sticks (<em>mᵉqoššeš ʿēṣîm</em>). <em>Wayyiqrāʾ ʾēleyhā wayyōʾmar qᵉḥî-nāʾ lî mᵉʿaṭ-mayim bakkᵉlî wᵉʾešṯeh</em> — he called to her and asked for a little water in a vessel to drink. The request begins with the least — water — before escalating to food.</p>',
    "11": '<p><em>wattēleḵ lāqaḥat wayyiqrāʾ ʾēleyhā wayyōʾmar qᵉḥî-nāʾ lî paṯ-leḥem bᵉyāḏēḵ</em> — as she went to get it, he called again and asked for a piece of bread as well. The escalation of request tests the widow\'s hospitality. Her immediate compliance with the water request but the pause before bread (she must explain her situation in v.12) reveals the text\'s narrative pacing: the water was easy to give; the bread will require a miracle.</p>',
    "12": '<p><em>ḥay YHWH ʾĕlōhayiḵ ʾim-yeš-lî māṣôg</em> — as YHWH your God lives, I have nothing baked. The widow\'s oath formula invokes <em>YHWH ʾĕlōhayiḵ</em> — YHWH your God (not \'my God\' — she is Phoenician, outside the covenant). She swears by the prophet\'s God, acknowledging his deity\'s existence without personal covenant membership. Her situation: a handful of flour in a jar (<em>kap-qemeḥ bakkad</em>) and a little oil in a jug (<em>mᵉʿaṭ-šemen baṣṣappāḥaṯ</em>) — the minimum for one final meal before death by starvation.</p>',
    "13": '<p><em>wayyōʾmer ʾēleyhā ʾēlîyāhû ʾal-tîrʾî</em> — Elijah said to her, do not be afraid. The prophetic reassurance formula (<em>ʾal-tîrʾî</em>) before the miracle command recurs throughout the prophetic narratives (cf. 2 Kgs 4:8–37). <em>ʿăśî ḵaddāḇār ʾaḵ ʿăśî-lî mišṣām ʾūgāh qᵉṭannāh bāriʾšōnāh</em> — but first make me a small cake from it and bring it out. The \'first-for-me\' command requires priority hospitality to the prophet, testing the depth of her compliance with the divine commission to feed him (v.9).</p>',
    "14": '<p><em>kî-ḵōh ʾāmar YHWH ʾĕlōhê yiśrāʾēl kad-qemeḥ lōʾ tiḵleh wᵉṣappāḥaṯ-haššemen lōʾ tiḥsar</em> — for thus says YHWH the God of Israel: the jar of flour will not be used up (<em>lōʾ tiḵleh</em>, will not be exhausted) and the jug of oil will not run dry (<em>lōʾ tiḥsar</em>, will not lack/fail). The divine oracle guarantees the miracle in advance of compliance. The two negatives with <em>lōʾ</em> + imperfect express permanent ongoing supply, not a one-time refill. <em>ʿAḏ yôm tēṯ-YHWH gešem ʿal-pᵉnê hāʾădāmāh</em> — until the day YHWH sends rain on the face of the earth — the miracle is temporally bounded by the drought oracle, connecting Zarephath provision to the Carmel confrontation to come.</p>',
    "15": '<p><em>wattēleḵ wattaʿaś kidbar ʾēlîyāhû</em> — she went and did according to Elijah\'s word. The obedience formula applies now to the widow, paralleling the formula used for Elijah (v.5). <em>Wattōʾkal hîʾ wᵉhûʾ ûḇêṯāh yāmîm</em> — she and Elijah and her household ate for many days. The tripartite beneficiaries (widow, prophet, household) and the open-ended duration (<em>yāmîm</em>, days — many days) indicate the miracle was sustained provision, not a single instance.</p>',
    "16": '<p><em>kad-qemeḥ lōʾ-ḵālāṯāh wᵉṣappāḥaṯ-haššemen lōʾ-ḥāsēr kidbar YHWH ʾăšer dibber bᵉyad ʾēlîyāhû</em> — the jar of flour was not exhausted and the jug of oil did not fail, according to the word of YHWH that he had spoken through Elijah. The fulfillment report mirrors the oracle of v.14 with verbal precision — the same nouns (<em>kad-qemeḥ, ṣappāḥaṯ-haššemen</em>), the same negated verbs (<em>lōʾ ḵālāṯāh, lōʾ ḥāsēr</em>). The fulfillment formula (<em>kidbar YHWH ʾăšer dibber bᵉyad</em>) marks the miracle as prophetic-word confirmation.</p>',
    "17": '<p><em>wayyᵉhî ʾaḥar haddᵉḇārîm hāʾēlleh ḥālāh ben-hāʾišāh baʿălaṯ habbāyiṯ</em> — after these things the son of the woman who owned the house became ill. <em>Wayyᵉhî ḥolyô ḥāzāq mᵉʾōḏ ʿaḏ ʾăšer lōʾ-nôṯᵃrāh bô nᵉšāmāh</em> — his illness was so severe that no breath (<em>nᵉšāmāh</em>, H5397) remained in him. The term <em>nᵉšāmāh</em> (breath of life, the animating principle from Gen 2:7) is used here for its cessation — the child is clinically dead, not merely ill. The narrative escalation from provision miracle to resurrection sets up the climactic encounter.</p>',
    "18": '<p><em>wattōʾmer ʾel-ʾēlîyāhû mah-lî wālaḵ ʾîš hāʾĕlōhîm</em> — she said to Elijah, what is between me and you, O man of God? The formula <em>mah-lî wālaḵ</em> (what to me and to you?) is an idiom of social distancing, expressing that the relationship has produced an unwanted outcome. <em>Hābāʾṯā ʾēlay lᵉhazḵîr ʾeṯ-ʿăwōnî ûlᵉhamîṯ ʾeṯ-bᵉnî</em> — have you come to call my sin to remembrance and to kill my son? She interprets the death as divine punishment triggered by the prophet\'s presence — a recognition that proximity to a holy man makes sin visible before God. The theology of divine holiness exposing human sin through prophetic presence is consistent with the Deuteronomistic framework.</p>',
    "19": '<p><em>wayyōʾmer ʾēleyhā tᵉnî-lî ʾeṯ-bᵉnēḵ wayyiqqāḥēhû mibᵉḥêqāh</em> — give me your son. He took him from her arms (<em>mibᵉḥêqāh</em>, from her bosom/arms — the lap-embrace of nursing or mourning). <em>Wayyaʿălēhû ʾel-hāʿălîyyāh ʾăšer-hûʾ yōšēḇ šām wayyaśkîḇēhû ʾal-miṭṭāṯô</em> — he carried him up to the upper room where he was staying and laid him on his own bed. The upper room (<em>ʿălîyyāh</em>, H5944) is the private chamber of the guest; laying the child on the prophet\'s own bed enacts a transfer of prophetic life-force or intimate intercession.</p>',
    "20": '<p><em>wayyiqrāʾ ʾel-YHWH wayyōʾmar YHWH ʾĕlōhay hăgam ʿal-hāʾalmānāh ʾăšer-ʾănî miṯgôrēr ʿimmāh hārēʿōṯā lᵉhamîṯ ʾeṯ-bᵉnāh</em> — he cried to YHWH: YHWH my God, have you also brought evil upon the widow with whom I am staying, to kill her son? <em>Miṯgôrēr</em> (hithpael of <em>gûr</em>, to sojourn) — Elijah presents himself as a dependent guest; the death of his host\'s son would bring reproach on his prophetic mission. The prayer is a bold challenge to divine action, consistent with the prophetic tradition of complaint-petition (cf. Moses, Habakkuk).</p>',
    "22": '<p><em>wayyišmaʿ YHWH bᵉqôl ʾēlîyāhû wattāšāḇ nefesh-hayyeled ʿal-qirḇô wayyeḥî</em> — YHWH heard Elijah\'s voice, and the soul of the child (<em>nefesh-hayyeled</em>) returned to his inward parts (<em>ʿal-qirḇô</em>), and he revived (<em>wayyeḥî</em>). The term <em>nefesh</em> (H5315) returns to the body (<em>qereb</em>, H7130, the inner organs/interior) — the resurrection is anatomically described as the animating principle re-inhabiting the physical body. This is the first recorded resurrection in Scripture; the language of <em>nefesh</em>-return will recur in 2 Kgs 4:34–35 (Elisha) and Ezek 37 (valley of dry bones).</p>',
    "23": '<p><em>wayyiqqaḥ ʾēlîyāhû ʾeṯ-hayyeled wayyōrîḏēhû min-hāʿălîyyāh habbayᵉṯāh wayyittᵉnēhû lᵉʾimmô</em> — Elijah took the child and brought him down from the upper room into the house and gave him to his mother. The descent from the upper room mirrors the ascent of v.19 — the spatial movement (up for death/prayer, down for restoration) enacts the reversal. <em>Wayyōʾmer ʾēlîyāhû rᵉʾî ḥay bᵉnēḵ</em> — Elijah said, see, your son lives. The announcement is direct and without elaboration: <em>ḥay</em> (alive), confirmed by presentation.</p>',
    "24": '<p><em>wattōʾmer hāʾišāh ʾel-ʾēlîyāhû ʿattāh zeh yāḏaʿtî kî ʾîš ʾĕlōhîm ʾattāh</em> — the woman said, now I know that you are a man of God (<em>ʾîš ʾĕlōhîm</em>). The confession of the Sidonian widow mirrors the structural logic of the prophetic sign: the miracle authenticates the messenger. <em>Ûḏᵉḇar-YHWH bᵉpîḵā ʾĕmeṯ</em> — and the word of YHWH in your mouth is truth (<em>ʾĕmeṯ</em>, H571, faithfulness/reliability). The widow\'s conclusion is twofold: the prophet is genuine and YHWH\'s word is <em>ʾĕmeṯ</em> — the latter term carries the sense of durable reliability, not just factual accuracy. A Phoenician woman outside the covenant becomes a witness to YHWH\'s prophetic truthfulness.</p>'
  }
}

def main():
    existing = load_comm('mkt-original', '1kings')
    merge_comm(existing, KINGS1)
    save_comm('mkt-original', '1kings', existing)
    for ch in ['15', '16', '17']:
        print(f'  ch{ch}: {len(existing.get(ch, {}))} verses')

if __name__ == '__main__':
    main()
